diff --git a/ghost/core/core/server/api/endpoints/comment-likes.js b/ghost/core/core/server/api/endpoints/comment-likes.js
new file mode 100644
index 0000000000..3d579c5fe2
--- /dev/null
+++ b/ghost/core/core/server/api/endpoints/comment-likes.js
@@ -0,0 +1,34 @@
+// Endpoint for the admin API to return likers for a comment
+
+const commentsService = require('../../services/comments');
+
+/** @type {import('@tryghost/api-framework').Controller} */
+const controller = {
+    docName: 'comment_likes',
+    browse: {
+        headers: {
+            cacheInvalidate: false
+        },
+        options: [
+            'id',
+            'page',
+            'limit'
+        ],
+        validation: {
+            options: {
+                id: {
+                    required: true
+                }
+            }
+        },
+        // Use comment permissions - browsing likes is part of comment moderation
+        permissions: {
+            docName: 'comments'
+        },
+        query(frame) {
+            return commentsService.controller.getCommentLikes(frame);
+        }
+    }
+};
+
+module.exports = controller;

