    51→    #extractReportCountFilter(filterString) {
    52→        if (!filterString || !filterString.includes('count.reports')) {
    53→            return {filter: filterString, reportCount: undefined, mongoTransformer: undefined};
    54→        }
    55→
    56→        const parsed = nql(filterString).parse();
    57→        const [countReportsFilter, remainingFilter] = splitFilter(parsed, ['count.reports']);
    58→
    59→        // Convert count.reports to reportCount option
    60→        let reportCount;
    61→        if (countReportsFilter?.['count.reports'] !== undefined) {
    62→            const val = countReportsFilter['count.reports'];
    63→            if (typeof val === 'number') {
    64→                reportCount = {op: '=', value: val};
    65→            } else if (val.$gt !== undefined) {
    66→                reportCount = {op: '>', value: val.$gt};
    67→            } else if (val.$gte !== undefined) {
    68→                reportCount = {op: '>=', value: val.$gte};
    69→            } else if (val.$lt !== undefined) {
    70→                reportCount = {op: '<', value: val.$lt};
    71→            } else if (val.$lte !== undefined) {
    72→                reportCount = {op: '<=', value: val.$lte};
    73→            } else if (val.$ne !== undefined) {
    74→                reportCount = {op: '!=', value: val.$ne};
    75→            }
    76→        }
    77→
    78→        // If there's remaining filter, use transformer to replace parsed result
    79→        // Otherwise, no filter needed
    80→        if (remainingFilter && Object.keys(remainingFilter).length > 0) {
    81→            return {
    82→                filter: filterString, // Keep original string for NQL to parse
    83→                reportCount,
    84→                mongoTransformer: () => remainingFilter // Replace with our pre-split result
    85→            };
    86→        }
    87→
    88→        return {filter: undefined, reportCount, mongoTransformer: undefined};
    89→    }
